 1	import type { FC, ReactElement } from 'react';
 2	import { ConsoleTimestamp } from 'src/components/ConsoleTimestamp/ConsoleTimestamp';
 3	import { useForkliftTranslation } from 'src/utils/i18n';
 4	
 5	import type { K8sResourceCondition } from '@kubev2v/types';
 6	import { HelperText, HelperTextItem } from '@patternfly/react-core';
 7	import { Table, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
 8	
 9	/**
10	 * React Component to display a table of conditions.
11	 *
12	 * @component
13	 * @param {ConditionsProps} props - Props for the Conditions component.
14	 * @param {K8sResourceCondition[]} props.conditions - Array of conditions to be displayed.
15	 * @returns {ReactElement} A table displaying the provided conditions.
16	 */
17	export const ConditionsSection: FC<ConditionsProps> = ({ conditions }): ReactElement => {
18	  const { t } = useForkliftTranslation();
19	
20	  if (!conditions) {
21	    return (
22	      <HelperText>
23	        <HelperTextItem>{t('Conditions not found')}</HelperTextItem>
24	      </HelperText>
25	    );
26	  }
27	
28	  const getStatusLabel = (status: string) => {
29	    switch (status) {
30	      case 'True':
31	        return t('True');
32	      case 'False':
33	        return t('False');
34	      default:
35	        return status;
36	    }
37	  };
38	
39	  return (
40	    <>
41	      <Table aria-label="Expandable table" variant="compact">
42	        <Thead>
43	          <Tr>
44	            <Th width={10}>{t('Type')}</Th>
45	            <Th width={10}>{t('Status')}</Th>
46	            <Th width={20}>{t('Updated')}</Th>
47	            <Th width={10}>{t('Reason')}</Th>
48	            <Th> {t('Message')}</Th>
49	          </Tr>
50	        </Thead>
51	        <Tbody>
52	          {conditions.map((condition) => (
53	            <Tr key={condition.type}>
54	              <Td>{condition.type}</Td>
55	              <Td>{getStatusLabel(condition.status)}</Td>
56	              <Td>
57	                <ConsoleTimestamp timestamp={condition.lastTransitionTime} />
58	              </Td>
59	              <Td>{condition.reason}</Td>
60	              <Td modifier="truncate">{condition?.message ?? '-'}</Td>
61	            </Tr>
62	          ))}
63	        </Tbody>
64	      </Table>
65	    </>
66	  );
67	};
68	
69	/**
70	 * Type for the props of the Conditions component.
71	 *
72	 * @typedef {Object} ConditionsProps
73	 * @property {K8sResourceCondition[]} conditions - The conditions to be displayed.
74	 */
75	type ConditionsProps = {
76	  conditions?: K8sResourceCondition[];
77	};

